#!/usr/bin/env python3
# apply_deckbox.py — add Macbeth (a916) + Wonderland (a917) deck-box cover images
# to assets/assets.json (these were the two decks missing from the shelf).
# Raw base64 JPEG. Pairs with the updated game.src.html that wires window.DECKBOX.
# Usage from repo root:  python3 apply_deckbox.py  &&  python3 build.py
import json, os, sys
root=os.path.dirname(os.path.abspath(__file__)); AJ=os.path.join(root,"assets","assets.json")
NEW={
  "a916": "",
  "a917": "",
}

if not os.path.exists(AJ): sys.exit("[apply] assets/assets.json not found — run from repo root.")
assets=json.load(open(AJ))
def raw_only(v):
    i=v.find('base64,'); return v[i+7:] if i!=-1 else v
ch=[]
for k,v in NEW.items():
    nv=raw_only(v)
    if assets.get(k)!=nv: assets[k]=nv; ch.append(k)
json.dump(assets,open(AJ,"w"))
print(f"[apply] deck boxes -> added {sorted(ch) or '(none)'}")
print("[apply] done. Next: python3 build.py")
